/* == EXEMPLE =======================================
 * Approche inverse : sigfillset + sigdelset
 * sigfillset remplit tous les signaux, puis on
 * retire ceux qu'on ne veut pas.
 * ================================================= */
void example_inverse_mask(void) {
    sigset_t full;
    sigfillset(&full);
    sigdelset(&full, SIGUSR1);
    sigdelset(&full, SIGUSR2);
    printf("SIGINT  dans full: %d\n", sigismember(&full, SIGINT));
    printf("SIGUSR1 dans full: %d\n", sigismember(&full, SIGUSR1));
    printf("SIGUSR2 dans full: %d\n", sigismember(&full, SIGUSR2));
}
/* Resultat: SIGINT=1, SIGUSR1=0, SIGUSR2=0 */

